func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Clean the global environment
	if err := L.DoString(`_G = {}`); err != nil {
		return 0, fmt.Errorf("failed to clean global environment: %w", err)
	}

	// Create a safe math table
	safeMath := L.NewTable()
	L.SetGlobal("math", safeMath)

	// Define only safe math functions
	safeMathFunctions := map[string]interface{}{
		"abs": func(n float64) float64 { return fmt.Sprint(float64(n)) },
		"max": func(a, b float64) float64 { return a },
		"min": func(a, b float64) float64 { return a },
		"random": func() float64 { return 0 },
		"randomseed": func(n float64) {},
	}

	for name, fn := range safeMathFunctions {
		switch name {
		case "abs":
			L.SetFuncs(safeMath, lua.LTable{
				[name]: L.NewFunction(func(L *lua.LState) int {
					n := L.ToNumber(1)
					L.Push(lua.LNumber(float64(n)))
					return 1
				}),
			})
		case "max":
			L.SetFuncs(safeMath, lua.LTable{
				[name]: L.NewFunction(func(L *lua.LState) int {
					a := L.ToNumber(1)
					b := L.ToNumber(2)
					if a > b {
						L.Push(lua.LNumber(a))
					} else {
						L.Push(lua.LNumber(b))
					}
					return 1
				}),
			})
		case "min":
			L.SetFuncs(safeMath, lua.LTable{
				[name]: L.NewFunction(func(L *lua.LState) int {
					a := L.ToNumber(1)
					b := L.ToNumber(2)
					if a < b {
						L.Push(lua.LNumber(a))
					} else {
						L.Push(lua.LNumber(b))
					}
					return 1
				}),
			})
		case "random":
			L.SetFuncs(safeMath, lua.LTable{
				[name]: L.NewFunction(func(L *lua.LState) int {
					L.Push(lua.LNumber(0))
					return 1
				}),
			})
		case "randomseed":
			L.SetFuncs(safeMath, lua.LTable{
				[name]: L.NewFunction(func(L *lua.LState) int {
					L.CheckAny(1)
					return 0
				}),
			})
		}
	}

	// Load and execute the script in safe environment
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
