func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	L := lua.NewState()
	defer L.Close()

	// Load and run the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function
	L.GetGlobal("calculate_final_price")
	if L.Get(-1).Type() != lua.LTFunction {
		L.Pop(1)
		return 0, errors.New("calculate_final_price function not found in script")
	}

	// Create and populate the context table
	ctxTable := L.NewTable()
	for key, value := range ctx {
		L.Push(lua.LString(key))
		L.Push(lua.LNumber(value))
		L.SetTable(ctxTable, -2)
	}

	// Push the context table as argument and call the function
	L.Push(ctxTable)
	if err := L.Call(1, 1); err != nil {
		return 0, fmt.Errorf("error calling calculate_final_price: %w", err)
	}

	// Get the result
	result := L.Get(-1)
	L.Pop(1)

	// Convert result to float64
	if num, ok := result.(lua.LNumber); ok {
		return float64(num), nil
	}

	return 0, errors.New("calculate_final_price did not return a number")
}

